**Smart decimation — new JS functions added (before `drawFreqAxis`):**
```javascript
// Binary search helper
function callsLowerBound(target) {
  let lo = 0, hi = S.calls.length;
  while (lo < hi) {
    const mid = (lo + hi) >> 1;
    if (S.calls[mid].t0 < target) lo = mid + 1;
    else hi = mid;
  }
  return lo;
}

function drawCallOverlays(specW, H, viewEnd) {
  const startIdx = Math.max(0, callsLowerBound(S.viewStart - 0.3));
  const visible  = [];
  for (let i = startIdx; i < S.calls.length; i++) {
    const c = S.calls[i];
    if (c.t0 >= viewEnd) break;
    if (c.t1 > S.viewStart && !S.hiddenSpecies.has(c.species)) visible.push(c);
  }
  if (!visible.length) return;
  const SPARSE_THRESHOLD = 400;
  if (visible.length <= SPARSE_THRESHOLD) {
    for (const c of visible) drawCall(c, specW, H);
    return;
  }
  drawCallsBatched(visible, specW, H);
  const sel = S.selectedCall;
  if (sel && sel.t0 < viewEnd && sel.t1 > S.viewStart) drawCall(sel, specW, H);
  const hov = S.hoveredCall;
  if (hov && hov !== sel && hov.t0 < viewEnd && hov.t1 > S.viewStart) drawCall(hov, specW, H);
}

function drawCallsBatched(visible, specW, H) {
  const dimming = S.selectedSeqId !== null;
  const bySpecies = {};
  for (const c of visible) {
    if (!bySpecies[c.species]) bySpecies[c.species] = { col: c.color, normal: [], dimmed: [] };
    if (dimming && c.seq_id !== S.selectedSeqId) bySpecies[c.species].dimmed.push(c);
    else bySpecies[c.species].normal.push(c);
  }
  const speciesList = Object.keys(bySpecies);
  const meanBW = {};
  for (const sp of speciesList) {
    const all = [...bySpecies[sp].normal, ...bySpecies[sp].dimmed];
    meanBW[sp] = all.reduce((s, c) => s + (c.Fmax - c.Fmin), 0) / all.length;
  }
  speciesList.sort((a, b) => meanBW[b] - meanBW[a]);  // widest first = behind

  function mergeRects(calls) {  // input already t0-sorted, no re-sort needed
    if (!calls.length) return [];
    const out = [];
    for (const c of calls) {
      const x0 = Math.floor(tToX(c.t0)), x1 = Math.ceil(tToX(c.t1));
      const y0 = Math.floor(fToY(c.Fmax)), y1 = Math.ceil(fToY(c.Fmin));
      if (out.length && x0 <= out[out.length - 1].x1) {
        const last = out[out.length - 1];
        last.x1 = Math.max(last.x1, x1);
        last.y0 = Math.min(last.y0, y0);
        last.y1 = Math.max(last.y1, y1);
      } else {
        out.push({ x0, x1, y0, y1 });
      }
    }
    return out;
  }
  if (S.showBoxes) {
    for (const sp of speciesList) {
      const { col, normal, dimmed } = bySpecies[sp];
      for (const [calls, isDimmed] of [[dimmed, true], [normal, false]]) {
        if (!calls.length) continue;
        const rects = mergeRects(calls);
        ctx.globalAlpha = isDimmed ? 0.05 : 0.18;
        ctx.fillStyle = col;
        ctx.beginPath();
        for (const r of rects) ctx.rect(r.x0, r.y0, r.x1 - r.x0, r.y1 - r.y0);
        ctx.fill();
        ctx.globalAlpha = isDimmed ? 0.10 : 0.65;
        ctx.strokeStyle = col;
        ctx.lineWidth = 0.9;
        ctx.beginPath();
        for (const r of rects) ctx.rect(r.x0, r.y0, r.x1 - r.x0, r.y1 - r.y0);
        ctx.stroke();
      }
    }
    ctx.globalAlpha = 1;
  }
}
```

**`trim_call_contour()` — Python function added before `try_load_cache()`:**
```python
def trim_call_contour(c):
    """Remove frequency-floor artifacts (< 20 kHz) from call contour and tighten Fmin/Fmax."""
    cnt = c.get("contour")
    if not cnt or len(cnt) < 2:
        return
    freqs = np.array([pt[1] for pt in cnt])
    mask    = freqs >= 20.0
    trimmed = [pt for pt, m in zip(cnt, mask) if m]
    if len(trimmed) == 0:
        return
    if len(trimmed) == 1:
        f = float(freqs[mask][0])
        c["contour"] = [[cnt[0][0], f], [cnt[-1][0], f]]
        c["Fmin"]    = round(f - 2.0, 2)
        c["Fmax"]    = round(f + 2.0, 2)
        return
    c["contour"] = trimmed
    tf = [pt[1] for pt in trimmed]
    new_lo = float(np.min(tf))
    new_hi = float(np.max(tf))
    if new_hi - new_lo < 1.0:
        pad    = (1.0 - (new_hi - new_lo)) / 2
        new_lo -= pad;  new_hi += pad
    c["Fmin"] = round(new_lo, 2)
    c["Fmax"] = round(new_hi, 2)
```

