  const RING_SIZE = 1_920_000;   // 10 s at 192 kHz
  // SAB layout: Int32[0]=readFrame, [1]=writeFrame, [2]=playing, [3]=rateX1000
  // Float32 data at byte offset 16
  class BatPlayerProcessor extends AudioWorkletProcessor {
    constructor (options) {
      super();
      const { sab, srcSr } = options.processorOptions;
      this._ctrl  = new Int32Array(sab, 0, 4);
      this._data  = new Float32Array(sab, 16, RING_SIZE);
      this._srcSr = srcSr;
      this._pos   = 0.0;
    }
    process (_inputs, outputs) {
      const ch0 = outputs[0][0];
      const ch1 = outputs[0][1];
      const n   = ch0.length;
      if (!Atomics.load(this._ctrl, 2)) {
        ch0.fill(0); if (ch1) ch1.fill(0);
        Atomics.store(this._ctrl, 0, Math.floor(this._pos));
        return true;
      }
      const rate = Atomics.load(this._ctrl, 3) / 1000;
      const step = (this._srcSr / sampleRate) * rate;
      const writeFrame = Atomics.load(this._ctrl, 1);
      let pos = this._pos;
      for (let i = 0; i < n; i++) {
        const f0 = Math.floor(pos);
        if (writeFrame - f0 < 2) { ch0[i] = 0; if (ch1) ch1[i] = 0; pos += step; continue; }
        const frac = pos - f0;
        const i0 = f0 % RING_SIZE;
        const i1 = (f0 + 1) % RING_SIZE;
        const s = this._data[i0] + frac * (this._data[i1] - this._data[i0]);
        ch0[i] = s; if (ch1) ch1[i] = s;
        pos += step;
      }
      this._pos = pos;
      Atomics.store(this._ctrl, 0, Math.floor(pos));
      return true;
    }
  }
