        const frac = pos - f0;
        const i0 = f0 % RING_SIZE, i1 = (f0 + 1) % RING_SIZE;
        const s = this._data[i0] + frac * (this._data[i1] - this._data[i0]);
        this._last = s;
        ch0[i] = s * this._gain;
        if (ch1) ch1[i] = s * this._gain;
        pos += step;
      }
