import AppKit
import Foundation

// Render emoji at device-pixel level (no HiDPI scaling)
func renderEmoji(_ emoji: String, px: Int) -> Data? {
    // Use a CGContext directly to avoid HiDPI doubling
    let cs = CGColorSpace(name: CGColorSpace.sRGB)!
    guard let ctx = CGContext(
        data: nil, width: px, height: px,
        bitsPerComponent: 8, bytesPerRow: px * 4,
        space: cs,
        bitmapInfo: CGImageAlphaInfo.premultipliedFirst.rawValue | CGBitmapInfo.byteOrder32Big.rawValue
    ) else { return nil }

    ctx.clear(CGRect(x: 0, y: 0, width: px, height: px))

    let nsCtx = NSGraphicsContext(cgContext: ctx, flipped: false)
    NSGraphicsContext.current = nsCtx

    let font = NSFont(name: "Apple Color Emoji", size: CGFloat(px) * 0.82) ?? NSFont.systemFont(ofSize: CGFloat(px))
    let attrs: [NSAttributedString.Key: Any] = [.font: font]
    let str = NSAttributedString(string: emoji, attributes: attrs)
    let strSz = str.size()
    str.draw(at: NSPoint(x: (CGFloat(px) - strSz.width) / 2.0,
                         y: (CGFloat(px) - strSz.height) / 2.0))

    NSGraphicsContext.current = nil

    guard let cgImg = ctx.makeImage() else { return nil }
    let rep = NSBitmapImageRep(cgImage: cgImg)
    return rep.representation(using: .png, properties: [:])
}

let sizes = [16, 32, 48, 64]
var pngDatas: [(Int, Data)] = []
for sz in sizes {
    if let png = renderEmoji("🦇", px: sz) {
