python3 - <<'EOF'
import json, collections

with open('/tmp/chrome_trace2.json') as f:
    data = json.load(f)

events = data.get('traceEvents', data.get('events', []))
chunks = [e for e in events if e.get('name') == 'ProfileChunk']

all_nodes = {}
all_samples, all_deltas = [], []
for chunk in chunks:
    d = chunk.get('args', {}).get('data', {})
    cp = d.get('cpuProfile', {})
    for node in cp.get('nodes', []):
        all_nodes[node['id']] = node
    all_samples.extend(cp.get('samples', []))
    all_deltas.extend(d.get('timeDeltas', []))

parent = {}
for nid, node in all_nodes.items():
    for child_id in node.get('children', []):
        parent[child_id] = nid

def sname(node):
    fn = node.get('callFrame', {})
    name = fn.get('functionName', '') or '(anon)'
    url  = fn.get('url', '').split('/')[-1].split('?')[0]
    return f"{name}[{url}]" if url else name

def full_stack(nid):
    stack = []
    while nid is not None:
        node = all_nodes.get(nid)
        if not node: break
        stack.append(sname(node))
        nid = parent.get(nid)
    return stack

self_time = collections.defaultdict(float)
for sid, delta in zip(all_samples, all_deltas):
    node = all_nodes.get(sid)
    if node: self_time[sname(node)] += delta

def callers_of(target, top=12):
    """Who calls target? (parent frame when target is leaf)"""
    caller_t = collections.defaultdict(float)
    for sid, delta in zip(all_samples, all_deltas):
        node = all_nodes.get(sid)
        if not node or sname(node) != target: continue
        stack = full_stack(sid)
        # find first JS caller above target
        for frame in stack[1:]:
            if frame not in ('(program)', '(root)', '(idle)', target):
                caller_t[frame] += delta
                break
    return sorted(caller_t.items(), key=lambda x: -x[1])[:top]

total_t = sum(self_time.values())

for target in ['set innerHTML', 'drawCallRug[render.js]', 'set font', 'clearTimeout', 'fillRect']:
    t = self_time.get(target, 0)
    print(f"\n=== {target}  ({t/1000:.0f}ms, {t/total_t*100:.1f}%) — top callers ===")
    for caller, ct in callers_of(target):
        print(f"    {ct/1000:6.1f}ms  {caller[:100]}")
EOF

