    def maptile_proxy(s, z, x, y):
        key = (s, z, x, y)
        if key not in _TILE_CACHE:
            if s not in ('a', 'b', 'c', 'd'): s = 'a'
            url = f"https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}.png"
